// // This module performs a bitwise OR operation on two 16-bit inputs A and B, and outputs the result. The enable signal controls whether the output is active; when low, the output is set to all ones.
module BitwiseAND(
    input [15:0] A,
    input [15:0] B,
    input enable,
    output reg [15:0] Y
);
    always @(*) begin
        if (enable) begin
            Y = A & B;
        end else begin
            Y = 16'b0;
        end
    end
endmodule
